"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6789],{73494:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>o,contentTitle:()=>l,default:()=>d,frontMatter:()=>s,metadata:()=>r,toc:()=>c});const r=JSON.parse('{"id":"guides/physics-features","title":"Making Bullets Feel Real","description":"There\'s a version of a shooter that technically works \u2014 bullets fire, hit things, deal damage \u2014 but doesn\'t feel right. Something about the projectiles is weightless. They travel in a laser-straight line, ignore wind, never tumble, and arrive at 300 studs exactly as crisply as they left the barrel.","source":"@site/docs/guides/physics-features.md","sourceDirName":"guides","slug":"/guides/physics-features","permalink":"/Vetra/docs/guides/physics-features","draft":false,"unlisted":false,"editUrl":"https://github.com/Vel136/Vetra/edit/master/docs/guides/physics-features.md","tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2},"sidebar":"defaultSidebar","previous":{"title":"Why Your Bullets Miss","permalink":"/Vetra/docs/guides/why-bullets-miss"},"next":{"title":"Networking and Trust","permalink":"/Vetra/docs/guides/networking"}}');var i=n(74848),a=n(28453);const s={sidebar_position:2},l="Making Bullets Feel Real",o={},c=[{value:"Gravity and Bullet Drop",id:"gravity-and-bullet-drop",level:2},{value:"Drag \u2014 Why Bullets Slow Down",id:"drag--why-bullets-slow-down",level:2},{value:"Supersonic and Subsonic Profiles",id:"supersonic-and-subsonic-profiles",level:2},{value:"Magnus Effect \u2014 The Curveball",id:"magnus-effect--the-curveball",level:2},{value:"Gyroscopic Drift",id:"gyroscopic-drift",level:2},{value:"Tumble \u2014 When Bullets Stop Flying",id:"tumble--when-bullets-stop-flying",level:2},{value:"Fragmentation",id:"fragmentation",level:2},{value:"Coriolis Effect",id:"coriolis-effect",level:2},{value:"Putting It Together",id:"putting-it-together",level:2}];function h(e){const t={admonition:"admonition",code:"code",em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",p:"p",pre:"pre",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"making-bullets-feel-real",children:"Making Bullets Feel Real"})}),"\n",(0,i.jsxs)(t.p,{children:["There's a version of a shooter that technically works \u2014 bullets fire, hit things, deal damage \u2014 but doesn't ",(0,i.jsx)(t.em,{children:"feel"})," right. Something about the projectiles is weightless. They travel in a laser-straight line, ignore wind, never tumble, and arrive at 300 studs exactly as crisply as they left the barrel."]}),"\n",(0,i.jsx)(t.p,{children:"It functions. It doesn't feel like a gun."}),"\n",(0,i.jsx)(t.p,{children:'The gap between "technically works" and "feels real" is physics. Not complicated physics \u2014 a few forces applied incrementally that change how the bullet travels through the air. This page explains each one: what it is, why it matters, and when you\'d actually use it.'}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"gravity-and-bullet-drop",children:"Gravity and Bullet Drop"}),"\n",(0,i.jsx)(t.p,{children:"This one you probably already have. A bullet fired horizontally doesn't stay horizontal \u2014 it falls. The further the target, the lower you need to aim."}),"\n",(0,i.jsxs)(t.p,{children:["Vetra applies gravity through the acceleration term in its kinematic formula. The default is ",(0,i.jsx)(t.code,{children:"workspace.Gravity"})," pointing downward, read at the time the behavior is built:"]}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"-- Default \u2014 uses workspace.Gravity automatically\r\nlocal Behavior = Vetra.BehaviorBuilder.new()\r\n    :Physics()\r\n        :MaxDistance(800)\r\n    :Done()\r\n    :Build()\n"})}),"\n",(0,i.jsx)(t.p,{children:"If you're building a zero-gravity map, a space level, or an underwater area with reduced gravity, override it:"}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:":Physics()\r\n    :Gravity(Vector3.new(0, -5, 0))  -- 5 studs/s\xb2 downward \u2014 floaty, underwater feel\r\n:Done()\n"})}),"\n",(0,i.jsxs)(t.p,{children:["Bullet drop is the baseline. Everything else layered on top makes it feel ",(0,i.jsx)(t.em,{children:"specific"})," rather than generic."]}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"drag--why-bullets-slow-down",children:"Drag \u2014 Why Bullets Slow Down"}),"\n",(0,i.jsx)(t.p,{children:"In a vacuum, a bullet would travel the same speed across any distance. In air, it doesn't."}),"\n",(0,i.jsx)(t.p,{children:"Drag is the resistance the air pushes back with. The faster you go, the more it pushes. A supersonic bullet bleeds speed quickly as it compresses the air in front of it. A subsonic bullet slows more gently. Shotgun pellets, which are spherical and blunt, decelerate far faster than the tapered projectile from a rifle."}),"\n",(0,i.jsx)(t.p,{children:"This matters for gameplay in three ways."}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Damage falloff."})," If you tie damage to velocity, a bullet that has slowed down to 60% of its firing speed deals less damage. Long-range hits naturally do less damage than close-range ones without needing a separate distance-based falloff system."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Lead and arc."})," At 800 studs, a slow-moving subsonic round has had several seconds to drop and decelerate. Players aiming at moving targets have to lead more. That's skill-testing in a way that hitscan can never replicate."]}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Feel."})," A rifle that feels snappy and penetrating at close range but requires careful aim at long range, purely because of physics, feels like a rifle. Not a magic wand with a gun skin."]}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"local Behavior = BehaviorBuilder.new()\r\n    :Physics()\r\n        :MaxDistance(800)\r\n        :MinSpeed(30)\r\n    :Done()\r\n    :Drag()\r\n        :Coefficient(0.003)\r\n        :Model(BehaviorBuilder.DragModel.G7)   -- long boat-tail, modern rifle standard\r\n        :SegmentInterval(0.05)                 -- recalculate drag every 50ms\r\n    :Done()\r\n    :Build()\n"})}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.strong,{children:"Choosing a drag model."})," The ",(0,i.jsx)(t.code,{children:":Model()"})," setter controls which drag curve is used. Always pass a value from ",(0,i.jsx)(t.code,{children:"BehaviorBuilder.DragModel"})," rather than a raw string \u2014 typos on raw strings pass the type checker silently and only fail at ",(0,i.jsx)(t.code,{children:":Build()"}),"."]}),"\n",(0,i.jsxs)(t.p,{children:["For most rifles and modern guns, ",(0,i.jsx)(t.code,{children:"BehaviorBuilder.DragModel.G7"})," is the right choice. It models a long boat-tail projectile \u2014 the standard reference for contemporary small-arms ballistics. For shotgun slugs or blunt projectiles, ",(0,i.jsx)(t.code,{children:"G6"})," applies more drag. For pistols and hollow points, ",(0,i.jsx)(t.code,{children:"G8"}),". For muskets and round shot, ",(0,i.jsx)(t.code,{children:"GL"}),' (the "lead ball" model) gives the heavy, arcing feel of pre-rifled weapons.']}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.code,{children:"Quadratic"})," is the default and is physically accurate for most situations where historical accuracy isn't required \u2014 drag proportional to speed squared. For pure gameplay tuning, it's often all you need."]}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"supersonic-and-subsonic-profiles",children:"Supersonic and Subsonic Profiles"}),"\n",(0,i.jsx)(t.p,{children:"Real bullets behave differently depending on whether they're moving faster or slower than the speed of sound."}),"\n",(0,i.jsx)(t.p,{children:"A supersonic bullet is creating a shockwave in front of it. The drag profile is different. The acoustic signature is the iconic crack followed by the thump of the shot \u2014 the crack arriving first because it travelled with the bullet, the thump arriving later from the muzzle. Ballistically, the transition from supersonic to subsonic is a zone of instability where the bullet can yaw, deflect, and lose accuracy."}),"\n",(0,i.jsx)(t.p,{children:"Vetra tracks whether a bullet is supersonic (above 343 studs/s) and lets you configure different physics for each regime:"}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"local Behavior = BehaviorBuilder.new()\r\n    :Drag()\r\n        :Coefficient(0.002)\r\n        :Model(BehaviorBuilder.DragModel.G7)\r\n    :Done()\r\n    :SpeedProfiles()\r\n        :Thresholds({ 343 })\r\n        :Supersonic()\r\n            :DragCoefficient(0.0015)    -- lower drag pushing through compressed air\r\n        :Done()\r\n        :Subsonic()\r\n            :DragCoefficient(0.004)     -- higher drag in the unstable transition zone\r\n            :Restitution(0.4)           -- bounces are sloppier when slow\r\n            :NormalPerturbation(0.06)   -- more scatter on surface contact\r\n        :Done()\r\n    :Done()\r\n    :Build()\r\n\r\nSignals.OnSpeedThresholdCrossed:Connect(function(context, threshold, velocity)\r\n    -- swap tracer colour, change fire sound, etc.\r\nend)\n"})}),"\n",(0,i.jsx)(t.p,{children:'For most games this level of detail is optional. But if you\'re building a milsim-adjacent experience or want long-range shots to have a distinct feel from close-range ones, speed profiles are what separate "simulated" from "simulated well."'}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"magnus-effect--the-curveball",children:"Magnus Effect \u2014 The Curveball"}),"\n",(0,i.jsx)(t.p,{children:"A spinning bullet moving through air doesn't travel straight. It curves."}),"\n",(0,i.jsx)(t.p,{children:"The force is perpendicular to both the spin axis and the velocity \u2014 the Magnus effect. It's why a baseball pitcher can throw a curveball. It's why real-world rifles exhibit spin drift \u2014 bullets fired from right-hand twist barrels drift slightly right over long distances. It's why a well-hit topspin tennis ball dips faster than you'd expect."}),"\n",(0,i.jsx)(t.p,{children:"In a game, this is useful in a few ways. You can build trick-shot mechanics. You can make specific weapons have a characteristic drift that skilled players need to account for. You can create a gun that literally curves its shots around cover."}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"local Behavior = BehaviorBuilder.new()\r\n    :Magnus()\r\n        :SpinVector(Vector3.new(0, 0, 1) * 300)  -- rightward spin, 300 rad/s\r\n        :Coefficient(0.0001)\r\n        :SpinDecayRate(0.05)    -- spin decays 5% per second as air slows it\r\n    :Done()\r\n    :Build()\n"})}),"\n",(0,i.jsx)(t.admonition,{title:"Start small",type:"caution",children:(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.code,{children:"MagnusCoefficient"})," is extremely sensitive. The force is ",(0,i.jsx)(t.code,{children:"Cm \xd7 (SpinVector \xd7 Velocity)"})," \u2014 at 600 studs/s with a spin rate of 300, even ",(0,i.jsx)(t.code,{children:"0.0001"})," produces visible drift. Start at ",(0,i.jsx)(t.code,{children:"0.00005"})," and work up incrementally. Going straight to ",(0,i.jsx)(t.code,{children:"0.001"})," will produce dramatic swerving that looks more like a homing missile than a bullet."]})}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"gyroscopic-drift",children:"Gyroscopic Drift"}),"\n",(0,i.jsxs)(t.p,{children:["Magnus drift is the ",(0,i.jsx)(t.em,{children:"lateral"})," curl caused by spin. Gyroscopic drift is the ",(0,i.jsx)(t.em,{children:"directional yaw"})," caused by the same spin interacting with the bullet's own precession around its velocity axis."]}),"\n",(0,i.jsx)(t.p,{children:"The practical difference: Magnus curves the path cleanly. Gyroscopic drift adds a slow, continuous lateral wander \u2014 subtle at short range, accumulating into noticeable deviation at long range."}),"\n",(0,i.jsx)(t.p,{children:"Real bullets from right-hand rifling drift slightly right and slightly up at long range. This is the combination of gyroscopic precession and Magnus effect. For a milsim game this is a compelling detail. For most games it's noise."}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"local Behavior = BehaviorBuilder.new()\r\n    :GyroDrift()\r\n        :Rate(0.4)    -- lateral acceleration in studs/s\xb2\r\n        -- :Axis() not set \u2014 defaults to world UP (right-hand rifling)\r\n    :Done()\r\n    :Build()\n"})}),"\n",(0,i.jsx)(t.p,{children:"Use this sparingly. It's most effective as a barely-perceptible force that snipers notice at extreme range \u2014 not as something that requires overcorrection on every shot."}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"tumble--when-bullets-stop-flying",children:"Tumble \u2014 When Bullets Stop Flying"}),"\n",(0,i.jsx)(t.p,{children:"A stable bullet is an aerodynamic bullet. The pointy end leads, the drag is low, the flight is predictable."}),"\n",(0,i.jsx)(t.p,{children:"A tumbling bullet is a bullet that has lost that stability. It's yawing, pitching \u2014 presenting its side to the airflow instead of its nose. Drag spikes. Accuracy collapses. The path becomes chaotic."}),"\n",(0,i.jsx)(t.p,{children:"This can happen when a bullet slows down below the speed that its rotational stabilisation can maintain. It can happen when a bullet passes through a soft target and exits destabilised. Either way, a tumbling bullet behaves completely differently from a stable one."}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"local Behavior = BehaviorBuilder.new()\r\n    :Pierce()\r\n        :Max(1)\r\n        :Filter(function(ctx, result, vel) return true end)\r\n    :Done()\r\n    :Tumble()\r\n        :OnPierce(true)          -- begin tumbling immediately after first pierce\r\n        :DragMultiplier(4.0)     -- drag multiplied by 4 \u2014 slows down fast\r\n        :LateralStrength(8)      -- chaotic lateral acceleration in studs/s\xb2\r\n        -- :SpeedThreshold() not set \u2014 pierce-based onset only\r\n        -- :RecoverySpeed() not set \u2014 once tumbling, permanent\r\n    :Done()\r\n    :Build()\r\n\r\nSignals.OnTumbleBegin:Connect(function(context, velocity)\r\n    -- visual: swap tracer to a tumbling sprite, change audio\r\nend)\n"})}),"\n",(0,i.jsx)(t.p,{children:'The result: bullets that exit a target are fast and predictable. Bullets that exit are slower, erratic, and do less damage at range \u2014 which is physically accurate. It turns pierce from "bullet ignores one wall" into "bullet changes character after passing through something."'}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"fragmentation",children:"Fragmentation"}),"\n",(0,i.jsx)(t.p,{children:"When a round hits and breaks apart, it sends shards outward in a cone. Fragmentation simulates this by spawning child bullets at the pierce point, each flying in a slightly different direction."}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"local Behavior = BehaviorBuilder.new()\r\n    :Pierce()\r\n        :Max(1)\r\n        :Filter(function(ctx, result, vel) return true end)\r\n    :Done()\r\n    :Fragmentation()\r\n        :OnPierce(true)\r\n        :Count(5)         -- five fragments\r\n        :Deviation(20)    -- spread within a 20-degree half-angle cone\r\n    :Done()\r\n    :Build()\r\n\r\nSignals.OnBranchSpawned:Connect(function(parentContext, childContext)\r\n    -- inherit a fraction of the parent's damage\r\n    childContext.UserData.Damage = parentContext.UserData.Damage * 0.25\r\n    childContext.UserData.IsFragment = true\r\nend)\n"})}),"\n",(0,i.jsxs)(t.p,{children:["Each fragment is a fully live cast. It can bounce, it can hit things, it fires ",(0,i.jsx)(t.code,{children:"OnHit"})," independently. If you want fragments that have their own drag and tumble, that's available too \u2014 either set it on the shared behavior the fragments inherit, or intercept ",(0,i.jsx)(t.code,{children:"OnBranchSpawned"})," and fire new casts with custom behavior immediately."]}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"coriolis-effect",children:"Coriolis Effect"}),"\n",(0,i.jsx)(t.p,{children:"The Coriolis effect is the deflection caused by Earth's rotation. A bullet fired north in the northern hemisphere drifts slightly east. Fired south, it drifts west. At the equator the drift is purely horizontal. At the poles, it rotates the bullet's ground track."}),"\n",(0,i.jsx)(t.p,{children:"In a real weapon at real-world distances and velocities, the Coriolis effect is real but tiny \u2014 irrelevant at combat ranges, detectable at extreme long range by specialist snipers. In a game, it can be exaggerated into a visible, tactile mechanic."}),"\n",(0,i.jsxs)(t.p,{children:["This is a ",(0,i.jsx)(t.strong,{children:"map-level setting"}),", not a bullet-level one. Every bullet fired through the same solver is affected equally \u2014 it's a property of the simulated environment, not the weapon."]}),"\n",(0,i.jsx)(t.pre,{children:(0,i.jsx)(t.code,{className:"language-lua",children:"-- Arctic map \u2014 latitude 75\xb0, 1200\xd7 exaggeration\r\nSolver:SetCoriolisConfig(75, 1200)\r\n\r\n-- Equatorial map \u2014 latitude 0\xb0, east/west drift only\r\nSolver:SetCoriolisConfig(0, 800)\r\n\r\n-- Turn it off for standard maps (default)\r\nSolver:SetCoriolisConfig(45, 0)\n"})}),"\n",(0,i.jsxs)(t.p,{children:["At scale ",(0,i.jsx)(t.code,{children:"1000"}),", Coriolis is clearly perceptible at ~300 studs. At ",(0,i.jsx)(t.code,{children:"3000"})," it's a dominant force players must actively compensate for. It's a useful differentiator for maps that want to feel geographically grounded, or as a hardmode modifier in competitive modes."]}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsx)(t.h2,{id:"putting-it-together",children:"Putting It Together"}),"\n",(0,i.jsxs)(t.p,{children:["None of these features are mandatory. A simple bounce-and-pierce setup without drag will work perfectly well for most shooters. The physics features exist for when you want the weapon to feel like ",(0,i.jsx)(t.em,{children:"that specific weapon"})," \u2014 not just a projectile with hitboxes."]}),"\n",(0,i.jsxs)(t.p,{children:["A sniper rifle that starts supersonic, transitions to subsonic at range, drifts slightly right from spin drift, and requires leading against moving targets at long range \u2014 that's a ",(0,i.jsx)(t.em,{children:"character"}),". Players learn its specific feel. Mastering it becomes part of the skill expression."]}),"\n",(0,i.jsx)(t.p,{children:"The right level of simulation for your game is a creative decision, not a technical one. Start with the minimum that makes the weapon feel right. Add physics one feature at a time until it feels like what you were imagining."})]})}function d(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(h,{...e})}):h(e)}},28453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>l});var r=n(96540);const i={},a=r.createContext(i);function s(e){const t=r.useContext(a);return r.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function l(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),r.createElement(a.Provider,{value:t},e.children)}}}]);